//! Hybrid post-quantum [key encapsulation
//! mechanism](https://en.wikipedia.org/wiki/Key_encapsulation_mechanism)
//! (KEM) based on ML-KEM and ristretto25519.
//!
//! The [`rustls`] package already uses such a hybrid kem (X25519MLKEM768) for PQ KX, but does not
//! expose this to us.  So instead of adding an additional package to pull in X25519MLKEM768,
//! we implement our own hybrid KEM using the implementations of ML-KEM and ristretto25519
//! already in our dependency tree.
//!
//! # Usage
//!
//! To establish a [`SharedSecret`] between, say, Alice and Bob, Alice first generates
//! a **decapsulation key** using [`DecapKey::generate`].  She keeps this key private, but sends
//! the associated **encapsulation key** (obtained via [`DecapKey::encap_key`]) to Bob.
//!
//! Using this [`EncapKey`], Bob can generate a [`CiphertextBytes`]-[`SharedSecret`] pair using
//! [`EncapKey::encap`] **encapsulating** the shared secret into the **ciphertext**.
//!
//! The shared secret can be retrieved, or **decapsulated**, from the ciphertext using Alice's
//! decapsulation key, via [`DecapKey::decap`].

use aws_lc_rs::kem as mlkem;
use curve25519_dalek::ristretto::CompressedRistretto;

use crate::common::elgamal::{self, Encoding as _};
use crate::common::secret;
use crate::misc::error::{Opaque, OPAQUE};
use crate::misc::serde_ext::bytes_wrapper::B64;
use crate::phcrypto;

/// Decapsulation key, the 'private key' of the KEM.  Generate using [`DecapKey::generate`].
#[derive(Debug)]
pub struct DecapKey {
    ml: mlkem::DecapsulationKey,

    /// Cached ML-KEM encapsulation key.  
    ///
    /// The [`mlkem::DecapsulationKey`] type is a bit weird: it either contains just the
    /// decapsulation key (when read from bytes via [`mlkem::DecapsulationKey::new`] *or*
    /// it contains both an encapsulation and decapsulation key (when generated via
    /// [`mlkem::DecapsulationKey::generate`].)
    ///
    /// So to deal with the former case, we include the encapsulation key here as well.
    ml_ek: mlkem::EncapsulationKey,
    ec: elgamal::PrivateKey,
}

/// Encapsulation key, the 'public key' of the KEM.  Can be obtained via [`DecapKey::encap_key`].
#[derive(Debug)]
pub struct EncapKey {
    ml: mlkem::EncapsulationKey,
    ec: elgamal::PublicKey,
}

/// Encoded form of [`DecapKey`].
#[derive(Clone, Debug, serde::Serialize, serde::Deserialize, zeroize::ZeroizeOnDrop)]
pub struct DecapKeyBytes {
    ml: B64,
    /// ML-KEM encapsulation-key bytes; see [`DecapKey::ml_ek`].
    ml_ek: B64,
    /// Scalar bytes.
    ec: B64,
}

/// Encoded form of [`EncapKey`].
#[derive(Clone, Debug, PartialEq, Eq, serde::Serialize, serde::Deserialize)]
pub struct EncapKeyBytes {
    ml: B64,
    /// [`CompressedRistretto`] bytes.
    ec: B64,
}

/// Encrypted [`SharedSecret`].  Create using [`EncapKey::encap`] and
/// decrypt using [`DecapKey::decap`].
#[derive(Clone, Debug, PartialEq, Eq, serde::Serialize, serde::Deserialize)]
pub struct CiphertextBytes {
    ml: B64,
    /// [`CompressedRistretto`] bytes.
    ec: B64,
}

/// Holds shared secrets generated by this KEM.
#[derive(Clone, Debug, zeroize::ZeroizeOnDrop)]
pub struct SharedSecret {
    inner: [u8; 32],
}

impl DecapKey {
    /// Generates a [`DecapKey`].  Expensive.
    pub fn generate() -> Result<Self, Opaque> {
        let ml = mlkem::DecapsulationKey::generate(&mlkem::ML_KEM_768)?;
        Ok(Self {
            ml_ek: ml.encapsulation_key()?,
            ml,
            ec: elgamal::PrivateKey::random(),
        })
    }

    /// Returns the associated [`EncapKey`].  Deterministic and cheap.
    pub fn encap_key(&self) -> EncapKey {
        // Getting the encapsulation_key via self.ml.encapsulation_key is fastest,
        // but it might not be there.
        let ml = self.ml.encapsulation_key().unwrap_or_else(|_| {
            mlkem::EncapsulationKey::new(
                &mlkem::ML_KEM_768,
                self.ml_ek
                    .key_bytes()
                    .expect("failed to retrieve encapsulation key bytes")
                    .as_ref(),
            )
            .expect("cached invalid encapsulation key")
        });
        EncapKey {
            ml,
            ec: self.ec.public_key().clone(),
        }
    }

    /// Decapsulates ciphertext, recovering the [`SharedSecret`] within.  Expensive.
    pub fn decap(&self, ct: &CiphertextBytes) -> Result<SharedSecret, Opaque> {
        let ss_ml = self.ml.decapsulate(mlkem::Ciphertext::from(&ct.ml[..]))?;

        let ec_bytes: [u8; 32] = (&ct.ec[..]).try_into()?;
        let pk =
            elgamal::PublicKey::try_from(CompressedRistretto(ec_bytes)).map_err(|()| OPAQUE)?;
        let ss_ec = self.ec.shared_secret(&pk);

        Ok(phcrypto::kem_shared_secret(&ss_ml, &ss_ec))
    }

    /// Encodes for storage.
    pub fn encode(&self) -> Result<DecapKeyBytes, Opaque> {
        Ok(DecapKeyBytes {
            ml: to_b64(self.ml.key_bytes()?.as_ref()),
            ml_ek: to_b64(self.ml_ek.key_bytes()?.as_ref()),
            ec: to_b64(self.ec.as_scalar().to_bytes()),
        })
    }
}

impl DecapKeyBytes {
    /// Decodes into [`DecapKey`].  Expensive.
    pub fn decode(&self) -> Result<DecapKey, Opaque> {
        Ok(DecapKey {
            ml: mlkem::DecapsulationKey::new(&mlkem::ML_KEM_768, &self.ml[..])?,
            ml_ek: mlkem::EncapsulationKey::new(&mlkem::ML_KEM_768, &self.ml_ek[..])?,
            ec: elgamal::PrivateKey::from_slice(&self.ec[..]).ok_or(OPAQUE)?,
        })
    }
}

impl EncapKey {
    /// Creates a [`SharedSecret`] and a [`CiphertextBytes`] encapsulating it.  Expensive.
    pub fn encap(&self) -> Result<(CiphertextBytes, SharedSecret), Opaque> {
        let (ct_ml, ss_ml) = self.ml.encapsulate()?;

        let ephemeral_sk = elgamal::PrivateKey::random();
        let ss_ec = ephemeral_sk.shared_secret(&self.ec);

        let ct = CiphertextBytes {
            ml: to_b64(ct_ml),
            ec: to_b64(ephemeral_sk.public_key().to_bytes()),
        };
        Ok((ct, phcrypto::kem_shared_secret(&ss_ml, &ss_ec)))
    }

    /// Encodes this key.  Cheap.
    pub fn encode(&self) -> Result<EncapKeyBytes, Opaque> {
        Ok(EncapKeyBytes {
            ml: to_b64(self.ml.key_bytes()?.as_ref()),
            ec: to_b64(self.ec.to_bytes()),
        })
    }
}

impl EncapKeyBytes {
    /// Decodes into [`EncapKey`].
    pub fn decode(&self) -> Result<EncapKey, Opaque> {
        Ok(EncapKey {
            ml: mlkem::EncapsulationKey::new(&mlkem::ML_KEM_768, &self.ml[..])?,
            ec: {
                let bytes: [u8; 32] = (&self.ec[..]).try_into()?;
                elgamal::PublicKey::try_from(CompressedRistretto(bytes)).map_err(|()| OPAQUE)?
            },
        })
    }
}

impl From<[u8; 32]> for SharedSecret {
    fn from(inner: [u8; 32]) -> Self {
        Self { inner }
    }
}

impl secret::DigestibleSecret for SharedSecret {
    fn as_bytes(&self) -> &[u8] {
        &self.inner
    }
}

/// Wraps a byte slice as a base64-serializing blob.
fn to_b64(bytes: impl AsRef<[u8]>) -> B64 {
    serde_bytes::ByteBuf::from(bytes.as_ref().to_vec()).into()
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::common::secret::DigestibleSecret as _;

    #[test]
    fn hybrid_roundtrip() {
        let dk = DecapKey::generate().unwrap();
        let ek = dk.encap_key();

        let (ct, ss_sender) = ek.encap().unwrap();
        let ss_recipient = dk.decap(&ct).unwrap();

        assert_eq!(ss_sender.as_bytes(), ss_recipient.as_bytes());
    }

    #[test]
    fn encode_decode_roundtrip() {
        let dk = DecapKey::generate().unwrap();

        // Decapsulation key survives an encode/decode trip (config persistence).
        let dk2 = dk.encode().unwrap().decode().unwrap();
        // Encapsulation key likewise (wire), and both keys still agree on a fresh secret.
        let ek = dk.encap_key().encode().unwrap().decode().unwrap();

        let (ct, ss_sender) = ek.encap().unwrap();
        assert_eq!(ss_sender.as_bytes(), dk2.decap(&ct).unwrap().as_bytes());
    }

    #[test]
    fn bytes_serde_roundtrip() {
        let dk = DecapKey::generate().unwrap();
        let ek_bytes = dk.encap_key().encode().unwrap();

        let json = serde_json::to_string(&ek_bytes).unwrap();
        let ek_bytes2: EncapKeyBytes = serde_json::from_str(&json).unwrap();

        assert_eq!(ek_bytes, ek_bytes2);
    }

    #[test]
    fn decap_key_bytes_serde_roundtrip() {
        let dk_bytes = DecapKey::generate().unwrap().encode().unwrap();
        let json = serde_json::to_string(&dk_bytes).unwrap();
        // DecapKeyBytes isn't PartialEq, so round-trip via re-serialize.
        let dk_bytes2: DecapKeyBytes = serde_json::from_str(&json).unwrap();
        assert_eq!(serde_json::to_string(&dk_bytes2).unwrap(), json);
    }

    #[test]
    fn ciphertext_bytes_serde_roundtrip() {
        let dk = DecapKey::generate().unwrap();
        let (ct, _) = dk.encap_key().encap().unwrap();
        let json = serde_json::to_string(&ct).unwrap();
        let ct2: CiphertextBytes = serde_json::from_str(&json).unwrap();
        assert_eq!(ct, ct2);
    }

    /// Pins encoding.  (See [`print_test_vectors`] for the source.)
    #[test]
    fn pinned_vectors() {
        use base64ct::Encoding as _;

        const DK_JSON: &str = r#"{"ml":"","ml_ek":"","ec":"u+coWbaISlx2hr7pA5LmWPGg6FZC8pIX+kOC+v/MGgA="}"#;
        const EK_JSON: &str = r#"{"ml":"","ec":"oh0u4IZUZXQvAbdr1492EdP0RWVFocTi7vPDCFcLsUc="}"#;
        const CT_JSON: &str = r#"{"ml":"","ec":"3H9cUtMTfKCSXae/d2Xb7NYCSeUdUBuIarhJAKb95VM="}"#;
        const SS_B64: &str = "4bpge1ouyjzuygcFzRK62n18Pz8Jidt+Olcpq/02d34=";

        let dk_bytes: DecapKeyBytes = serde_json::from_str(DK_JSON).unwrap();
        let ek_bytes: EncapKeyBytes = serde_json::from_str(EK_JSON).unwrap();
        let ct: CiphertextBytes = serde_json::from_str(CT_JSON).unwrap();
        let ss_expected = base64ct::Base64::decode_vec(SS_B64).unwrap();

        // Serde format is stable: parsed values re-serialize to the captured JSON.
        assert_eq!(serde_json::to_string(&dk_bytes).unwrap(), DK_JSON);
        assert_eq!(serde_json::to_string(&ek_bytes).unwrap(), EK_JSON);
        assert_eq!(serde_json::to_string(&ct).unwrap(), CT_JSON);

        // Encapsulation key derived from the decoded DK matches the captured EK.
        let dk = dk_bytes.decode().unwrap();
        assert_eq!(dk.encap_key().encode().unwrap(), ek_bytes);

        // Decap of the captured ciphertext yields the captured shared secret.
        assert_eq!(dk.decap(&ct).unwrap().as_bytes(), ss_expected.as_slice());
    }

    /// Prints fresh values to regenerate [`pinned_vectors`].  Run with
    /// `cargo test --lib common::kem::tests::print_test_vectors -- --ignored --nocapture`.
    #[test]
    #[ignore]
    fn print_test_vectors() {
        use base64ct::Encoding as _;
        let dk = DecapKey::generate().unwrap();
        let dk_bytes = dk.encode().unwrap();
        let ek_bytes = dk.encap_key().encode().unwrap();
        let (ct, ss) = dk.encap_key().encap().unwrap();

        println!("DK_JSON: {}", serde_json::to_string(&dk_bytes).unwrap());
        println!("EK_JSON: {}", serde_json::to_string(&ek_bytes).unwrap());
        println!("CT_JSON: {}", serde_json::to_string(&ct).unwrap());
        println!(
            "SS_B64:  {}",
            base64ct::Base64::encode_string(ss.as_bytes())
        );
    }

    #[test]
    fn distinct_keys_disagree() {
        let dk = DecapKey::generate().unwrap();
        let other = DecapKey::generate().unwrap();

        let (ct, ss_sender) = dk.encap_key().encap().unwrap();
        // Decapsulating with the wrong key yields a different secret, never an error.
        assert_ne!(ss_sender.as_bytes(), other.decap(&ct).unwrap().as_bytes());
    }
}
